class Solution {
public:
    bool checkSubarraySum(vector<int>& nums, int k) {
        unordered_map<int, int> prefixSum;
        prefixSum[0] = -1;
        int sum = 0;
        for (int i = 0; i < nums.size(); i++) {
            sum = (sum + nums[i]) % k;
            if (prefixSum.find(sum) != prefixSum.end()) {
                if (i - prefixSum[sum] >= 2) {
                    return true;
                }
            } else {
                prefixSum[sum] = i;
            }
        }
        return false;
    }
};

